<# .SYNOPSIS Offline regression for enterprise Skill/MCP intake. #>
param([switch]$PassThru)
$ErrorActionPreference='Stop';$root=(Resolve-Path(Join-Path $PSScriptRoot '..\..')).Path;$tmp=Join-Path $root '.qianlima\tmp\skill-intake';New-Item -ItemType Directory -Path $tmp -Force|Out-Null;$gate=Join-Path $PSScriptRoot 'invoke-skill-intake-gate.ps1';$hash='b'*64
function W($n,$v){$p=Join-Path $tmp $n;[IO.File]::WriteAllText($p,($v|ConvertTo-Json -Depth 12),[Text.UTF8Encoding]::new($false));$p};function Intake($id,$type='skill') {[ordered]@{artifact_id=$id;artifact_type=$type;source_type='git_url';source_ref='https://example.invalid/repo.git';version='1.0.0';content_sha256=$hash;commit_sha='abcdef123456';author_ref='owner:example';dependency_manifest_hash='deps:sha256:test';data_classification='internal_sanitized';declared_capabilities=@('format_document');requested_permissions=@('read_selected_file');dependency_network_approved=$false;change_flags=@()}};function Scan(){[ordered]@{scanner_id='offline-static';scanner_version='1';scanned_at=(Get-Date).ToUniversalTime().ToString('o');artifact_content_sha256=$hash;dependency_manifest_hash='deps:sha256:test';offline_static_completed=$true;network_used=$false;llm_mode='none';observed_capabilities=@('format_document');findings=@();rescan_reasons=@();transport='stdio';authentication_present=$false;bind_address='';required_on_conversation_start=$false}}
function Run($name,$i,$s){$ip=W "$name-intake.json" $i;$sp=W "$name-scan.json" $s;$out=& powershell.exe -NoProfile -ExecutionPolicy Bypass -File $gate -IntakePath $ip -ScanReportPath $sp -PassThru 2>&1;[pscustomobject]@{code=$LASTEXITCODE;text=($out-join"`n")}}
$safe=Run safe (Intake safe) (Scan);$mismatchScan=Scan;$mismatchScan.observed_capabilities=@('format_document','enumerate_user_home','read_environment_variables','network_access');$mismatch=Run mismatch (Intake mismatch) $mismatchScan;$mediumScan=Scan;$mediumScan.findings=@([ordered]@{id='f1';severity='medium';rule='dynamic_import'});$medium=Run medium (Intake medium) $mediumScan;$networkScan=Scan;$networkScan.network_used=$true;$network=Run network (Intake network) $networkScan;$mcpScan=Scan;$mcpScan.transport='http';$mcpScan.bind_address='0.0.0.0';$mcp=Run mcp (Intake mcp mcp_connector) $mcpScan;$confidential=Intake confidential;$confidential.data_classification='confidential_reference_only';$llmScan=Scan;$llmScan.llm_mode='external_llm';$llm=Run llm $confidential $llmScan
$changed=Intake changed;$changed.change_flags=@('dependency_changed');$stale=Run stale $changed (Scan)
$cases=@([pscustomobject]@{name='safe_scan_approved_but_not_installed';passed=($safe.code-eq0-and$safe.text-match'"status"\s*:\s*"approved"'-and$safe.text-match'"install_authorized"\s*:\s*false')},[pscustomobject]@{name='declared_vs_dangerous_observed_mismatch_denied';passed=($mismatch.code-ne0-and$mismatch.text-match'dangerous_undeclared_capability')},[pscustomobject]@{name='medium_finding_is_conditional';passed=($medium.code-eq0-and$medium.text-match'"status"\s*:\s*"conditional"')},[pscustomobject]@{name='no_llm_does_not_imply_no_dependency_network';passed=($network.code-ne0-and$network.text-match'unapproved_dependency_network_use')},[pscustomobject]@{name='unauthenticated_non_loopback_http_mcp_denied';passed=($mcp.code-ne0-and$mcp.text-match'unauthenticated_http_mcp_denied'-and$mcp.text-match'non_loopback_mcp_bind_denied')},[pscustomobject]@{name='confidential_source_external_llm_denied';passed=($llm.code-ne0-and$llm.text-match'external_llm_source_disclosure_denied')},[pscustomobject]@{name='change_requires_matching_rescan_evidence';passed=($stale.code-ne0-and$stale.text-match'required_rescan_evidence_missing')},[pscustomobject]@{name='minimum_contract_has_no_global_permissions';passed=($safe.text-match'"global_permissions"\s*:\s*\[\s*\]'-and$safe.text-match'"task_grant_required"\s*:\s*true')});$failed=@($cases|?{-not$_.passed});$r=[pscustomobject]@{passed=($failed.Count-eq0);cases=$cases;scanner_executed=$false;external_calls=$false;permissions_granted=$false};if($PassThru){$r|ConvertTo-Json -Depth 10}else{$cases|Format-Table -AutoSize};if($failed.Count){throw('Skill intake regression failed: '+(($failed.name)-join', '))}
